import React, { useState, useEffect, useRef, useCallback } from 'react';
import { supabase } from '../supabaseClient';

const STATUS_COLORS = {
  concept: '#8b5cf6', script: '#3b82f6', production: '#f59e0b',
  edit: '#f97316', review: '#ec4899', published: '#22c55e',
};
const STATUS_LABELS = {
  concept: 'Concept', script: 'Script', production: 'Production',
  edit: 'Edit', review: 'Review', published: 'Published',
};
const NETWORK_COLORS = {
  youtube: '#FF0000', instagram: '#E1306C', tiktok: '#00F2EA',
  facebook: '#1877F2', twitter: '#1DA1F2', threads: '#000000',
};
const NETWORK_ICONS = {
  youtube: '▶', instagram: '◉', tiktok: '♪',
  facebook: 'f', twitter: '𝕏', threads: '@',
};

export default function Calendar() {
  const [projects, setProjects] = useState([]);
  const [scheduledPosts, setScheduledPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingPosts, setLoadingPosts] = useState(false);
  const [viewDate, setViewDate] = useState(new Date());
  const [viewMode, setViewMode] = useState('month');
  const [filterStatus, setFilterStatus] = useState('all');
  const [showMetricool, setShowMetricool] = useState(true);
  const [metricoolError, setMetricoolError] = useState(null);
  const scrollRef = useRef(null);

  useEffect(() => {
    const timeout = setTimeout(() => setLoading(false), 5000);
    fetchProjects().finally(() => clearTimeout(timeout));
    return () => clearTimeout(timeout);
  }, []);

  const fetchMetricoolPosts = useCallback(async (start, end) => {
    setLoadingPosts(true);
    setMetricoolError(null);
    try {
      const startStr = start.toISOString().split('.')[0];
      const endStr = end.toISOString().split('.')[0];
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error('Not authenticated');
      const supabaseUrl = process.env.REACT_APP_SUPABASE_URL;
      const response = await fetch(
        `${supabaseUrl}/functions/v1/metricool-posts?start=${encodeURIComponent(startStr)}&end=${encodeURIComponent(endStr)}&timezone=America/Los_Angeles`,
        {
          headers: {
            'Authorization': `Bearer ${session.access_token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      if (!response.ok) {
        const err = await response.json().catch(() => ({}));
        throw new Error(err.error || `HTTP ${response.status}`);
      }
      const data = await response.json();
      setScheduledPosts(data.posts || []);
    } catch (err) {
      console.error('Metricool error:', err);
      setMetricoolError(err.message);
      setScheduledPosts([]);
    } finally {
      setLoadingPosts(false);
    }
  }, []);

  useEffect(() => {
    if (showMetricool) {
      const { start, end } = getDateRangeForFetch();
      fetchMetricoolPosts(start, end);
    }
  }, [viewDate, viewMode, showMetricool, fetchMetricoolPosts]);

  async function fetchProjects() {
    try {
      const { data, error } = await supabase
        .from('projects').select('*').order('start_date', { ascending: true });
      if (error) throw error;
      setProjects(data || []);
    } catch (err) {
      console.error('Error:', err);
      setProjects([]);
    } finally {
      setLoading(false);
    }
  }

  function getDateRangeForFetch() {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    if (viewMode === 'month') {
      return { start: new Date(year, month, 1), end: new Date(year, month + 1, 0, 23, 59, 59) };
    }
    const qStart = Math.floor(month / 3) * 3;
    return { start: new Date(year, qStart, 1), end: new Date(year, qStart + 3, 0, 23, 59, 59) };
  }

  function getDateRange() {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    if (viewMode === 'month') {
      const start = new Date(year, month, 1);
      const end = new Date(year, month + 1, 0, 23, 59, 59);
      return { start, end, days: end.getDate() };
    }
    const qStart = Math.floor(month / 3) * 3;
    const start = new Date(year, qStart, 1);
    const end = new Date(year, qStart + 3, 0, 23, 59, 59);
    const days = Math.ceil((end - start) / (1000 * 60 * 60 * 24)) + 1;
    return { start, end, days };
  }

  const { start: rangeStart, end: rangeEnd, days: totalDays } = getDateRange();

  function navigateView(direction) {
    const d = new Date(viewDate);
    if (viewMode === 'month') d.setMonth(d.getMonth() + direction);
    else d.setMonth(d.getMonth() + (direction * 3));
    setViewDate(d);
  }

  function getDays() {
    const days = [];
    const d = new Date(rangeStart);
    while (d <= rangeEnd) { days.push(new Date(d)); d.setDate(d.getDate() + 1); }
    return days;
  }
  const allDays = getDays();

  function getBarStyle(startDate, endDate) {
    const pStart = new Date(startDate);
    const pEnd = new Date(endDate);
    const barStart = pStart < rangeStart ? rangeStart : pStart;
    const barEnd = pEnd > rangeEnd ? rangeEnd : pEnd;
    if (barStart > rangeEnd || barEnd < rangeStart) return null;
    const startOffset = Math.max(0, (barStart - rangeStart) / 86400000);
    const duration = Math.max(1, (barEnd - barStart) / 86400000 + 1);
    return { left: `${(startOffset / totalDays) * 100}%`, width: `${(duration / totalDays) * 100}%` };
  }

  function getDotPosition(dateStr) {
    const d = new Date(dateStr);
    if (d < rangeStart || d > rangeEnd) return null;
    const offset = (d - rangeStart) / 86400000;
    return `${(offset / totalDays) * 100}%`;
  }

  function groupPostsByDate(posts) {
    const groups = {};
    posts.forEach(post => {
      const dateKey = post.publicationDate.dateTime.split('T')[0];
      if (!groups[dateKey]) groups[dateKey] = [];
      groups[dateKey].push(post);
    });
    return groups;
  }

  const filtered = projects.filter(p => {
    if (filterStatus !== 'all' && p.status !== filterStatus) return false;
    const pStart = new Date(p.start_date);
    const pEnd = new Date(p.deadline);
    return pStart <= rangeEnd && pEnd >= rangeStart;
  });

  const postsByDate = groupPostsByDate(scheduledPosts);

  const viewTitle = viewMode === 'month'
    ? viewDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })
    : `Q${Math.floor(viewDate.getMonth() / 3) + 1} ${viewDate.getFullYear()}`;

  function getPostDisplayText(post) {
    if (post.youtubeTitle) return post.youtubeTitle;
    if (post.text) return post.text.split('\n')[0].substring(0, 60);
    return 'Untitled post';
  }

  return (
    <div style={styles.page}>
      <div style={styles.topBar}>
        <div>
          <h1 style={styles.pageTitle}>Calendar</h1>
          <p style={styles.pageSubtitle}>
            {filtered.length} projects{showMetricool && ` · ${scheduledPosts.length} scheduled posts`}
          </p>
        </div>
      </div>

      <div style={styles.controlsRow}>
        <div style={styles.navControls}>
          <button onClick={() => navigateView(-1)} style={styles.navBtn}>←</button>
          <span style={styles.viewTitle}>{viewTitle}</span>
          <button onClick={() => navigateView(1)} style={styles.navBtn}>→</button>
          <button onClick={() => setViewDate(new Date())} style={styles.todayBtn}>Today</button>
        </div>
        <div style={styles.rightControls}>
          <button
            onClick={() => setShowMetricool(!showMetricool)}
            style={{ ...styles.metricoolToggle, ...(showMetricool ? styles.metricoolToggleActive : {}) }}
          >
            {loadingPosts ? '⟳' : '📅'} Metricool
          </button>
          <div style={styles.viewToggle}>
            <button onClick={() => setViewMode('month')}
              style={{ ...styles.viewBtn, ...(viewMode === 'month' ? styles.viewBtnActive : {}) }}>Month</button>
            <button onClick={() => setViewMode('quarter')}
              style={{ ...styles.viewBtn, ...(viewMode === 'quarter' ? styles.viewBtnActive : {}) }}>Quarter</button>
          </div>
        </div>
      </div>

      {metricoolError && showMetricool && (
        <div style={styles.errorBanner}>
          Metricool: {metricoolError}
          <button onClick={() => setMetricoolError(null)} style={styles.errorClose}>✕</button>
        </div>
      )}

      <div style={styles.filterRow}>
        <button onClick={() => setFilterStatus('all')}
          style={{ ...styles.filterBtn, ...(filterStatus === 'all' ? styles.filterBtnActive : {}) }}>All</button>
        {Object.keys(STATUS_COLORS).map(s => (
          <button key={s} onClick={() => setFilterStatus(s)}
            style={{ ...styles.filterBtn, ...(filterStatus === s ? { background: `${STATUS_COLORS[s]}20`, color: STATUS_COLORS[s], borderColor: `${STATUS_COLORS[s]}40` } : {}) }}>
            {STATUS_LABELS[s]}
          </button>
        ))}
      </div>

      <div style={styles.chartContainer} ref={scrollRef}>
        <div style={styles.dayHeaders}>
          <div style={styles.projectNameCol}>Project</div>
          <div style={styles.daysArea}>
            {allDays.map((day, i) => {
              const isToday = day.toDateString() === new Date().toDateString();
              const isWeekend = day.getDay() === 0 || day.getDay() === 6;
              const isFirstOfMonth = day.getDate() === 1;
              return (
                <div key={i} style={{
                  ...styles.dayHeader, width: `${100 / totalDays}%`,
                  color: isToday ? '#6366f1' : isWeekend ? 'rgba(255,255,255,0.2)' : 'rgba(255,255,255,0.35)',
                  fontWeight: isToday ? 700 : 400,
                  borderLeft: isFirstOfMonth && viewMode === 'quarter' ? '1px solid rgba(255,255,255,0.1)' : 'none',
                }}>
                  {viewMode === 'month' ? (
                    <><span style={{ fontSize: '10px' }}>{day.toLocaleDateString('en-US', { weekday: 'narrow' })}</span><span>{day.getDate()}</span></>
                  ) : (day.getDate() === 1 || day.getDate() === 15 ? <span>{day.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span> : null)}
                </div>
              );
            })}
          </div>
        </div>

        {loading ? (
          <p style={{ padding: '20px', color: 'rgba(255,255,255,0.35)' }}>Loading...</p>
        ) : (
          <>
            {filtered.length === 0 && !showMetricool && (
              <p style={{ padding: '20px', color: 'rgba(255,255,255,0.35)' }}>No projects in this date range.</p>
            )}

            {filtered.map(project => {
              const barStyle = getBarStyle(project.start_date, project.deadline);
              return (
                <div key={project.id} style={styles.chartRow}>
                  <div style={styles.projectNameCol}>
                    <div style={styles.chartProjectName}>{project.name}</div>
                    <div style={styles.chartProjectType}>
                      {project.type.replace('_', ' ')}{project.channel && ` · ${project.channel}`}
                    </div>
                  </div>
                  <div style={styles.daysArea}>
                    {allDays.map((day, i) => (
                      <div key={i} style={{
                        ...styles.gridCell, width: `${100 / totalDays}%`,
                        background: day.toDateString() === new Date().toDateString() ? 'rgba(99,102,241,0.08)'
                          : (day.getDay() === 0 || day.getDay() === 6) ? 'rgba(255,255,255,0.01)' : 'transparent',
                      }} />
                    ))}
                    {barStyle && (
                      <div style={{ ...styles.bar, ...barStyle, background: `linear-gradient(135deg, ${STATUS_COLORS[project.status]}, ${STATUS_COLORS[project.status]}99)` }}
                        title={`${project.name}: ${new Date(project.start_date).toLocaleDateString()} - ${new Date(project.deadline).toLocaleDateString()}`}>
                        <span style={styles.barLabel}>{project.name}</span>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}

            {showMetricool && scheduledPosts.length > 0 && (
              <>
                <div style={styles.sectionDivider}>
                  <div style={styles.projectNameCol}><div style={styles.sectionLabel}>📅 Scheduled Posts</div></div>
                  <div style={styles.daysArea}>
                    {allDays.map((day, i) => (
                      <div key={i} style={{ ...styles.gridCell, width: `${100 / totalDays}%`, background: 'rgba(255,255,255,0.02)' }} />
                    ))}
                  </div>
                </div>

                {Object.entries(postsByDate).sort(([a], [b]) => a.localeCompare(b)).map(([dateKey, posts]) => {
                  const dateObj = new Date(dateKey + 'T12:00:00');
                  if (dateObj < rangeStart || dateObj > rangeEnd) return null;
                  const rowHeight = Math.max(48, posts.length * 24 + 12);
                  return (
                    <div key={dateKey} style={{ ...styles.chartRow, minHeight: `${rowHeight}px` }}>
                      <div style={styles.projectNameCol}>
                        <div style={styles.chartProjectName}>
                          {dateObj.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
                        </div>
                        <div style={styles.chartProjectType}>{posts.length} post{posts.length > 1 ? 's' : ''}</div>
                      </div>
                      <div style={styles.daysArea}>
                        {allDays.map((day, i) => (
                          <div key={i} style={{
                            ...styles.gridCell, width: `${100 / totalDays}%`,
                            background: day.toDateString() === new Date().toDateString() ? 'rgba(99,102,241,0.08)' : 'transparent',
                          }} />
                        ))}
                        {posts.map((post, pi) => {
                          const left = getDotPosition(post.publicationDate.dateTime);
                          if (!left) return null;
                          const color = NETWORK_COLORS[post.network] || '#666';
                          const icon = NETWORK_ICONS[post.network] || '•';
                          const isPending = post.status === 'PENDING';
                          return (
                            <div key={post.id} style={{
                              position: 'absolute', left, top: `${4 + (pi * 24)}px`,
                              display: 'flex', alignItems: 'center', gap: '4px',
                              padding: '2px 8px 2px 6px',
                              background: `${color}20`, border: `1px solid ${color}40`,
                              borderRadius: '6px', fontSize: '10px', color, fontWeight: 600,
                              whiteSpace: 'nowrap', zIndex: 2,
                              cursor: post.publicUrl ? 'pointer' : 'default',
                              opacity: isPending ? 0.7 : 1,
                              maxWidth: `${Math.max(10, (100 / totalDays) * 4)}%`,
                              overflow: 'hidden', textOverflow: 'ellipsis',
                            }}
                              title={`${post.network.toUpperCase()} · ${isPending ? 'Pending' : 'Published'}\n${getPostDisplayText(post)}`}
                              onClick={() => post.publicUrl && window.open(post.publicUrl, '_blank')}>
                              <span style={{ fontSize: '11px', flexShrink: 0 }}>{icon}</span>
                              <span style={{ overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                {getPostDisplayText(post).substring(0, 30)}
                              </span>
                              {isPending && <span style={{ opacity: 0.6, flexShrink: 0 }}>⏳</span>}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </>
            )}
          </>
        )}
      </div>

      <div style={styles.legend}>
        <div style={styles.legendGroup}>
          <span style={styles.legendGroupLabel}>Projects:</span>
          {Object.entries(STATUS_COLORS).map(([status, color]) => (
            <div key={status} style={styles.legendItem}>
              <div style={{ ...styles.legendDot, background: color }} /><span>{STATUS_LABELS[status]}</span>
            </div>
          ))}
        </div>
        {showMetricool && (
          <div style={styles.legendGroup}>
            <span style={styles.legendGroupLabel}>Platforms:</span>
            {Object.entries(NETWORK_COLORS).map(([network, color]) => (
              <div key={network} style={styles.legendItem}>
                <div style={{ ...styles.legendDot, background: color }} />
                <span style={{ textTransform: 'capitalize' }}>{network}</span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

